### Description
Multi-quality HLS video where the URL is generated from a JSON object embedded in an iframe

The path to the master M3U8 file is a bit complicated to get to. Here's a semi-salvaging of the original JavaScript, slightly tweaked to work in Node (I know this was made in Python, but hopefully it will still be somewhat applicable)

```Node
var qualityTypes = [{
	bitrate : 2560,
	resolution : "1280x720",
	audio : 128,
	friendlyName : "720p"
}, {
	bitrate : 1536,
	resolution : "960x540",
	audio : 96,
	friendlyName : "540p"
}, {
	bitrate : 1024,
	resolution : "640x360",
	audio : 96,
	friendlyName : "360p"
}, {
	bitrate : 512,
	resolution : "480x270",
	audio : 64,
	friendlyName : "270p"
}, {
	bitrate : 256,
	resolution : "320x180",
	audio : 64,
	friendlyName : "180p"
}];

function data(input)
{
	this.data = input;
}

data.prototype.constructor = data;

var testRegex = /((ftp|https?):\/\/|(mailto:)?[A-Za-z0-9._%+-]+@)\S*[^\s\.\;\,\(\)\{\}\<\>]/;
var pathway = url.parse("");
var options = {
	urls : {
		videoStreaming : "https://legoprod-f.akamaihd.net",
		videoProgressive : "https://lc-mediaplayerns-live-s.legocdn.com",
		assets : "http://cache.lego.com/r/www",
		site : "http://www.lego.com/en-us"
	}
};
var asserterNames = ["mp4", "webm"];
var headers = {
	mp4: "video/mp4",
	webm: "video/webm"
};

data.prototype.createHtml5StreamingUrl = function(output, braces)
{
	var pagerNum = qualityTypes.reduce(function(Status, quality) {
	return Status ? Status + "," + quality.bitrate : quality.bitrate + "";
	}, "");
	
	var rreturn = output + concatenateString(this.data) + "_," + pagerNum + ",." + braces;
	return this.transformStreamingVideoUrl(rreturn);
};

function concatenateString(vidData)
{
	var path = [];
	path.push(vidData.ItemId);
	path.push(vidData.VideoId);
	path.push(vidData.Locale);
	path.push(vidData.VideoVersion);
	
	var concatenated = path.join("_");
	return vidData.hasOwnProperty("NetStoragePath") && !!vidData.NetStoragePath ? [vidData.NetStoragePath, concatenated].join("/") : [concatenated.substr(0, 2), concatenated.substr(2, 2), y].join("/");
};

data.prototype.transformStreamingVideoUrl = function(source)
{
    return this.trim(source) && (source = this.tokenizer(source), source = this.removeTrailingSlash(options.urls.videoStreaming) + source, source = this.format(source)), source;
};

data.prototype.tokenizer = function(string)
{
	return string = this.removeLeadingSlash(string), string = this.addLeadingSlash(string), string = this.removeTrailingSlash(string);
};

data.prototype.format = function(string)
{
	pathway = url.parse(string);
	var path = pathway.pathname;
	return path = path.toLowerCase(), path = this.addTrailingSlash(path), pathway.pathname = path, pathway.href;
};

data.prototype.trim = function(string) {
	return !testRegex.test(string);
};

data.prototype.removeTrailingSlash = function(string)
{
	return "/" == string.substr(-1, 1) && (string.length > 1 && (string = string.substr(0, string.length - 1))), string;
};

data.prototype.removeLeadingSlash = function(string)
{
	return "/" == string.substr(0, 1) && (string = string.substr(1)), string;
};

data.prototype.addLeadingSlash = function(num)
{
	return "/" !== num.substr(0, 1) && (num = "/" + num), num;
};

data.prototype.addTrailingSlash = function(path)
{
	if ("/" !== path.substr(-1)) if(-1 == path.split("/").pop().indexOf(".")) path += "/";
	return path;
};
```

